import React from 'react';
import Box from '@mui/material/Box';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

type Item = {
  label: string;
  value: number;
  color?: string;
};

type Props = {
  title: string;
  items: Item[];
};

export default function SimpleBarChart({ title, items }: Props) {
  const max = Math.max(1, ...items.map((i) => i.value));

  return (
    <Box sx={{ p: 2, bgcolor: 'white', borderRadius: 1, border: '1px solid rgba(0,0,0,0.12)' }}>
      <Typography variant="subtitle1" gutterBottom>
        {title}
      </Typography>
      <Stack spacing={1}>
        {items.map((i) => (
          <Stack key={i.label} spacing={0.5}>
            <Stack direction="row" spacing={1} alignItems="center">
              <Typography variant="body2" sx={{ minWidth: 160 }}>
                {i.label}
              </Typography>
              <Typography variant="body2">{i.value}</Typography>
            </Stack>
            <Box
              sx={{
                height: 10,
                width: `${Math.round((i.value / max) * 100)}%`,
                bgcolor: i.color ?? 'primary.main',
                borderRadius: 1,
              }}
            />
          </Stack>
        ))}
      </Stack>
    </Box>
  );
}
