import React from 'react';
import Box from '@mui/material/Box';
import FormControl from '@mui/material/FormControl';
import InputLabel from '@mui/material/InputLabel';
import MenuItem from '@mui/material/MenuItem';
import Select from '@mui/material/Select';
import Container from '@mui/material/Container';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

import AppCard from '../components/common/AppCard';
import DataTable, { Column } from '../components/common/DataTable';
import UserAlert from '../components/common/UserAlert';
import SimpleBarChart from '../components/dashboard/SimpleBarChart';
import { api } from '../services/api';
import type { Network } from '../types/entities';

export default function Dashboard() {
  const [networks, setNetworks] = React.useState<Network[]>([]);
  const [networkId, setNetworkId] = React.useState<number | ''>('');

  const [data, setData] = React.useState<Awaited<ReturnType<typeof api.getDashboard>> | null>(null);
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState<string | null>(null);

  React.useEffect(() => {
    let mounted = true;

    api
      .listNetworks()
      .then((nets) => {
        if (!mounted) return;
        setNetworks(nets);
      })
      .catch(() => {
        if (!mounted) return;
        setError("Impossible de charger les réseaux.");
      });

    return () => {
      mounted = false;
    };
  }, []);

  React.useEffect(() => {
    let mounted = true;
    setLoading(true);
    setError(null);

    api
      .getDashboard({ networkId: networkId === '' ? undefined : networkId })
      .then((d) => {
        if (!mounted) return;
        setData(d);
      })
      .catch(() => {
        if (!mounted) return;
        setError('Impossible de charger le dashboard.');
      })
      .finally(() => {
        if (!mounted) return;
        setLoading(false);
      });

    return () => {
      mounted = false;
    };
  }, [networkId]);

  const latestArticlesColumns: Column<{ id: number; title: string; publishedAt: string | null; networkId: number }>[] = [
    { key: 'id', header: 'ID', render: (a) => a.id },
    { key: 'title', header: 'Titre', render: (a) => a.title },
    { key: 'publishedAt', header: 'Publié le', render: (a) => a.publishedAt ?? '-' },
    { key: 'networkId', header: 'Réseau', render: (a) => a.networkId },
  ];

  const latestNotificationsColumns: Column<{ id: number; userId: number; articleId: number; type: string; sentAt: string }>[] = [
    { key: 'id', header: 'ID', render: (n) => n.id },
    { key: 'type', header: 'Type', render: (n) => n.type },
    { key: 'articleId', header: 'Article', render: (n) => n.articleId },
    { key: 'userId', header: 'User', render: (n) => n.userId },
    { key: 'sentAt', header: 'Envoyé le', render: (n) => n.sentAt },
  ];

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Stack spacing={2}>
        <AppCard title="Dashboard Admin">
          <Stack spacing={2}>
            <Stack direction={{ xs: 'column', md: 'row' }} spacing={2} alignItems={{ md: 'center' }}>
              <Typography variant="subtitle1" sx={{ flexGrow: 1 }}>
                Statistiques
              </Typography>
              <FormControl size="small" sx={{ minWidth: 220 }}>
                <InputLabel id="network-dashboard">Filtrer par réseau</InputLabel>
                <Select
                  labelId="network-dashboard"
                  label="Filtrer par réseau"
                  value={networkId}
                  onChange={(e) => {
                    const v = String(e.target.value);
                    setNetworkId(v === '' ? '' : Number(v));
                  }}
                >
                  <MenuItem value="">Tous</MenuItem>
                  {networks.map((n) => (
                    <MenuItem key={n.id} value={n.id}>
                      {n.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Stack>

            {loading ? <UserAlert severity="info" message="Chargement..." /> : null}
            {error ? <UserAlert severity="error" message={error} /> : null}

            {data ? (
              <Stack spacing={2}>
                <Stack direction={{ xs: 'column', md: 'row' }} spacing={2}>
                  <Box sx={{ flex: 1 }}>
                    <AppCard title="Articles">
                      <Typography variant="h4">{data.totals.articles}</Typography>
                    </AppCard>
                  </Box>
                  <Box sx={{ flex: 1 }}>
                    <AppCard title="Par status">
                      <Stack>
                        {Object.entries(data.byStatus).map(([k, v]) => (
                          <Typography key={k} variant="body2">
                            {k}: {v}
                          </Typography>
                        ))}
                      </Stack>
                    </AppCard>
                  </Box>
                  <Box sx={{ flex: 1 }}>
                    <AppCard title="Par réseau">
                      <Stack>
                        {data.byNetwork.map((r) => (
                          <Typography key={r.networkId} variant="body2">
                            {r.networkId}: {r.count}
                          </Typography>
                        ))}
                      </Stack>
                    </AppCard>
                  </Box>
                </Stack>

                <SimpleBarChart
                  title="Articles par catégorie"
                  items={data.byCategory.map((c) => ({ label: c.name, value: c.count }))}
                />

                <AppCard title="5 derniers articles publiés">
                  <DataTable columns={latestArticlesColumns} rows={data.latestPublished} />
                </AppCard>

                <AppCard title="Dernières notifications">
                  <DataTable columns={latestNotificationsColumns} rows={data.latestNotifications} />
                </AppCard>
              </Stack>
            ) : null}
          </Stack>
        </AppCard>
      </Stack>
    </Container>
  );
}
